import React, { useState, useEffect } from 'react';
import './App.css';
import Sidebar from './components/Sidebar';
import ChatWindow from './components/ChatWindow';
import axios from 'axios';

const API = axios.create({ baseURL: 'http://localhost:8000' });

function App() {
    const [loggedIn, setLoggedIn] = useState(false);
    const [username, setUsername] = useState('游客');
    const [messages, setMessages] = useState([]);
    const [input, setInput] = useState('');

    useEffect(() => {
        if (loggedIn) {
            API.get(`/api/history?username=${username}`)
                .then(res => {
                    const msgs = res.data.history.map(h => ({ sender: h.role, text: h.content }));
                    setMessages(msgs);
                })
                .catch(() => { });
        }
    }, [loggedIn, username]);

    const sendMessage = async () => {
        if (!input.trim()) return;
        const userMsg = { sender: 'user', text: input };
        setMessages(prev => [...prev, userMsg]);
        setInput('');

        try {
            const res = await API.post('/api/chat', {
                message: input,
                username,
                logged_in: loggedIn
            });
            const aiMsg = { sender: 'assistant', text: res.data.reply };
            setMessages(prev => [...prev, aiMsg]);
        } catch (err) {
            console.error(err);
        }
    };

    const clearHistory = async () => {
        if (loggedIn) {
            await API.post(`/api/clear-history?username=${username}`);
        }
        setMessages([]);
    };

    const fetchMistakes = async () => {
        try {
            const res = await API.get('/api/mistakes');
            setMessages(prev => [...prev, { sender: 'assistant', text: res.data.mistakes }]);
        } catch (err) {
            console.error(err);
        }
    };

    const fetchReport = async () => {
        try {
            const res = await API.get('/api/report');
            setMessages(prev => [...prev, { sender: 'assistant', text: res.data.report }]);
        } catch (err) {
            console.error(err);
        }
    };

    const downloadWorksheet = (answers) => {
        window.open(`http://localhost:8000/api/download-worksheet?answers=${answers}`);
    };

    return (
        <div className="h-screen flex bg-gradient-to-br from-pink-50 to-purple-100">
            <Sidebar
                loggedIn={loggedIn}
                username={username}
                setLoggedIn={setLoggedIn}
                setUsername={setUsername}
                onClearHistory={clearHistory}
                onFetchMistakes={fetchMistakes}
                onFetchReport={fetchReport}
                onDownloadWorksheet={downloadWorksheet}
            />
            <ChatWindow
                messages={messages}
                input={input}
                setInput={setInput}
                onSend={sendMessage}
            />
        </div>
    );
}

export default App;
